import fs from "node:fs";
import path from "node:path";
import { spawnSync } from "node:child_process";
import { pathToFileURL } from "node:url";
import YAML from "yaml";

const repoRoot = process.cwd();

function loadYaml(relativePath) {
  return YAML.parse(fs.readFileSync(path.join(repoRoot, relativePath), "utf8"));
}

function assert(condition, message) {
  if (!condition) throw new Error(message);
}

function assertIncludes(list, value, message) {
  assert(Array.isArray(list) && list.includes(value), message);
}

function runC004ArtifactValidator() {
  const result = spawnSync("python3", ["validators/c004_artifact_validator.py"], {
    cwd: repoRoot,
    encoding: "utf8",
  });
  assert(result.status === 0, result.stderr || result.stdout || "C-004 artifact validation failed");
}

function validateC004RerunRecords() {
  const candidates = loadYaml("records/candidates/R-004.yaml").candidates || [];
  const c004 = candidates.find((candidate) => candidate.candidate_id === "C-004-001");
  assert(c004?.active_attempt_id === "C-004-001-R2", "C-004 must remain on active attempt C-004-001-R2");
  assert(c004?.current_stage === "12_delivery_launch", "C-004 rerun must complete through delivery launch before publish approval");
  assert(c004?.founder_acceptance_status === "pass", "C-004 founder acceptance must pass after artifact repair");
  assert(c004?.last_rerun?.result === "pass_pending_marketplace_publish", "C-004 rerun must stop at pass_pending_marketplace_publish");
  assert(c004?.last_rerun?.external_publish_status === "not_run", "External marketplace publish must remain not_run");

  const qa = loadYaml("records/validation/QA-C-004-001-R2.yaml").qa_result;
  assert(qa?.derived_reorder_point_results?.status === "pass", "QA must include passing derived reorder point artifact results");
  assert(qa?.negative_on_hand_invariant_results?.status === "pass", "QA must include passing negative on-hand invariant results");
  assert(qa?.blank_formula_ready_capacity_results?.status === "pass", "QA must include passing blank formula-ready capacity results");
  assert(qa?.helper_behavior_walkthrough_results?.status === "pass", "QA must include passing helper walkthrough results");
  assert(qa?.publish_blockers?.status === "pass", "QA publish blockers must pass only after artifact validator passes");

  const founder = loadYaml("records/validation/FA-C-004-001-R2.yaml").founder_acceptance_simulation;
  assert(founder?.founder_acceptance_status === "pass", "Founder acceptance record must pass");
  assert(founder?.human_post_review_override?.status === "not_needed_after_repair", "Founder record must state no human override was needed after repair");
  assert(founder?.publish_blockers?.status === "pass", "Founder publish blockers must pass only after acceptance passes");
  assert((founder?.rejection_reasons || []).length === 0, "Founder acceptance pass must have no rejection reasons");

  const preMortem = loadYaml("records/validation/PM-C-004-001-R2.yaml").pre_mortem_failure_analysis;
  assert(preMortem?.status === "pass_watchlist_only", "Pre-mortem must pass with watchlist only");
  assert(Array.isArray(preMortem?.launch_blockers) && preMortem.launch_blockers.length === 0, "Pre-mortem launch blockers must be absent");
  assert(!preMortem?.missed_launch_blockers_after_human_review || preMortem.missed_launch_blockers_after_human_review.length === 0, "Pre-mortem must not record missed blockers after the repaired rerun");
  assert(preMortem?.product_logic_blocker_audit?.status === "pass", "Pre-mortem must audit product logic blockers");
  assert(preMortem?.helper_behavior_scenario_audit?.status === "pass", "Pre-mortem must audit helper behavior scenario");
  assert(preMortem?.decision === "pass_pending_marketplace_publish", "Pre-mortem decision must allow launch with watchlist only");

  const launch = loadYaml("records/validation/LR-C-004-001-R2.yaml").launch_package;
  assert(launch?.status === "pass_pending_marketplace_publish", "Launch package must stop at pass_pending_marketplace_publish");
  assert(launch?.publish_status === "pass_pending_marketplace_publish", "Launch publish status must await external marketplace approval");
  assert(launch?.passed_system === true, "Launch package must pass system checks");
  assert(launch?.prepublish_validation?.founder_acceptance === "pass", "Launch must require founder acceptance pass");
  assert(launch?.prepublish_validation?.pre_mortem_failure_analysis === "pass_watchlist_only", "Launch must require pre-mortem pass/watchlist only");
  assert(launch?.prepublish_validation?.publish_blockers_absent === true, "Launch must have no publish blockers");
  assert(launch?.publish_blockers?.status === "pass", "Launch publish blockers must pass");
  assert(launch?.external_publish_approval?.required === true, "External publish approval remains required");
  assert(launch?.external_publish_approval?.decision === "pending", "External publish approval must be pending, not executed");

  const listing = loadYaml("records/listing_creatives/LC-C-004-001-R2.yaml").listing_creative_assembly;
  assert(listing?.founder_acceptance_ref === "records/validation/FA-C-004-001-R2.yaml", "Listing must consume R2 founder acceptance");
  assert(listing?.publish_blockers?.status === "pass", "Listing creative blockers must pass");
}

